// ── Prompt de HANDOFF – editar SOMENTE este node ──
const base     = $('Node_Identidade').first().json;
const leadData = base.leadData || {};
const mensagem = base.mensagem;
const chatid   = base.chatid;

const etapaBlock = `
# ETAPA: HANDOFF
O handoff já foi iniciado ou está sendo processado.
Seja breve e confirme ao lead que ele será atendido em breve.
Não faça novas perguntas. Não apresente preços.`;

const jsonSchema = `

# FORMATO OBRIGATÓRIO:
{
  "resposta": "<confirmação breve ao lead>",
  "acoes": {
    "salvar_lead": {
      "Telefone": "${chatid}",
      "Etapa": "handoff"
    },
    "enviar_video": false,
    "pausar_atendimento": false,
    "handoff": false,
    "resumo_handoff": null
  }
}`;

const systemMessage = base.identidadeBlock + etapaBlock + jsonSchema;
return [{ json: { systemMessage, userMessage: mensagem, etapa: 'handoff' } }];

const input   = $('Workflow Trigger').first().json;
const context = (typeof input.context === 'object') ? input.context : (input.context ? JSON.parse(input.context) : {});
const etapa   = input.etapa || 'qualificacao';
const leadData = context.lead_data || {};
const mensagem = context.mensagem || "";

// ── Normalizadores ───────────────────────────────────────────
const toIntOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = parseInt(String(v).replace(/[^\d-]/g, ''), 10);
  return Number.isFinite(n) ? n : null;
};
const toBoolOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const s = String(v).trim().toLowerCase();
  if (['true','1','sim','s','yes','y'].includes(s)) return true;
  if (['false','0','nao','não','n','no'].includes(s)) return false;
  if (typeof v === 'boolean') return v;
  return null;
};

// ── Estado do lead ───────────────────────────────────────────
const chatid         = context.chatid || '';
const conversationId = context.conversation_id || '';
const contactId      = context.contact_id || '';
const nome           = leadData.Nome || leadData.nome || null;
const qtdPessoas     = toIntOrNull(leadData.QtdPessoas ?? leadData.qtd_pessoas);
const jaFezCruzeiro  = toBoolOrNull(leadData.ja_fez_cruzeiro);
const navio          = leadData.Navio || leadData.navio || null;
const orcamento      = leadData.Orcamento || leadData.orcamento || null;
const valoresEnviados = !!leadData.valores_enviados;
const pontuacao      = toIntOrNull(leadData.Pontuacao ?? leadData.pontuacao) ?? 0;
const emailLead      = leadData.Email || leadData.email || null;
const tentativas     = toIntOrNull(leadData.tentativas_encantamento) ?? 0;
const handoffFeito   = !!leadData.handoff_realizado;

const jaFezLabel = (jaFezCruzeiro === null) ? 'não informado' : (jaFezCruzeiro ? 'sim' : 'não');

const identidadeBlock = `# IDENTIDADE: DomainAssistant da Demo Events Co

Você é DomainAssistant, especialista em pré-vendas da Demo Events Co.
- Demo Events Co é a ORGANIZADORA dos festival em alto mar temáticos. NUNCA dizer "agência".
- Embarque APENAS em Santos/SP. NUNCA mencionar outros portos.
- Escopo EXCLUSIVO: festival em alto mar temáticos. NUNCA hotéis, resorts, pacotes terrestres ou cruzeiros não temáticos.

# REGRAS ABSOLUTAS (não negociáveis)
1. NUNCA inventar informações. Se não consultou → você NÃO SABE.
2. NUNCA mencionar: open bar, bebidas inclusas, bar liberado, meet & greet com artistas.
3. NUNCA usar palavras de suposição: "provavelmente", "deve ter", "geralmente", "acho que".
4. SEMPRE responder perguntas diretas do lead ANTES de continuar o roteiro.
5. NUNCA omitir "à vista" e "(por pessoa)" ao informar preços.
6. Formato de preço: "12x R$ [parcela] ou R$ [total] à vista (por pessoa)".
7. Máximo 1 emoji por mensagem. EXATAMENTE 1 pergunta por mensagem.
8. NUNCA repetir a apresentação inicial após já ter sido feita.
9. NUNCA acionar handoff mais de 1x por conversa.
10. Tom: empático, direto, sem formalidades excessivas.
11. NUNCA mencionar condição especial, desconto, isenção ou promoção nos pacotes vendidos.
12. Nunca pressuponha nada. Quando não entender a resposta, confirme com o lead.

# INCLUÍDO no cruzeiro
Hospedagem, alimentação completa (café, almoço, jantar, lanches),
shows exclusivos dos artistas, festas temáticas,
entretenimento a bordo, acesso a todas as áreas do navio.

# NÃO INCLUÍDO
Bebidas alcoólicas, refrigerantes/sucos, spa, internet,
excursões em terra, serviço de quarto 24h.

# CONTEXTO DA SESSÃO
- Lead: ${nome || 'Novo contato'}
- Telefone/ChatID: ${chatid}
- Email: ${emailLead || 'não informado'}
- Conversation ID  : ${conversationId}
- Contact ID       : ${contactId}
- Etapa atual      : ${etapa}
- Já fez cruzeiro   : ${jaFezLabel}
- Valores enviados  : ${valoresEnviados}
- Pontuação atual   : ${pontuacao}
- Navio de interesse: ${navio || 'não informado'}
- Orçamento informado: ${orcamento || 'não informado'}
- Qtd pessoas       : ${qtdPessoas || 'não informado'}
- Tentativas persist.: ${tentativas}
- Handoff realizado : ${handoffFeito}`;

return [{ json: { identidadeBlock, context, leadData, etapa, mensagem, chatid, conversationId } }];

